  ('social-worker-moex-02351', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '羅溫伯格與多格夫（Lowenberg & Dolgoff）倫理抉擇觀點中，第一優先原則是下列那一項？', '["最小傷害原則", "自主自由原則", "保護生命原則", "差別平等原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "9b8a3d37c0d1", "answer_pdf_sha1": "5df06a1a485f", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
